sql:
SELECT AVG(home_points + visitor_points) AS avg_points_scored
FROM games g
JOIN overtime_games og ON g.game_id = og.game_id;

SELECT AVG(g.attend) AS average_attendance
FROM games g
JOIN overtime_games og ON g.game_id = og.game_id;

external_knowledge:
- "Games that went into overtime" refers to games where the `overtime` column is set to 1;
- "Top scorer" refers to the player who scored the most points in a game;
- "Highest total points" refers to the cumulative points scored by a player across all overtime games.

